import React, { useEffect, useState } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshProducts, updateProductQuantity, isEditing, currentMovementId, movement, products }) => {
    const [product, setProduct] = useState({
        produto: '',
        tipo_movimentacao: 'entrada',
        quantidade: '',
        motivo: ''
    });

    useEffect(() => {
        if (isEditing) {
            setProduct({
                produto: movement.produto?.id || '',
                tipo_movimentacao: movement.tipo_movimentacao,
                quantidade: movement.quantidade,
                motivo: movement.motivo
            });
        } else {
            clearForm();
        }
    }, [isEditing, movement]);

    const clearForm = () => {
        setProduct({
            produto: '',
            tipo_movimentacao: 'entrada',
            quantidade: '',
            motivo: ''
        });
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setProduct({ ...product, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
    
        const selectedProduct = products.find(p => p.id === parseInt(product.produto));
    
        if (!selectedProduct) {
            alert("Por favor, selecione um produto válido.");
            return;
        }
    
        const dataToSend = {
            produto: selectedProduct, // Certifique-se de que está enviando o objeto correto
            tipo_movimentacao: product.tipo_movimentacao,
            quantidade: parseInt(product.quantidade),
            motivo: product.motivo,
        };
    
        console.log("Dados enviados:", dataToSend); // Log dos dados que estão sendo enviados
    
        try {
            if (isEditing) {
                await axios.put(`http://127.0.0.1:8000/api/movimentacoes/${currentMovementId}/`, dataToSend);
            } else {
                await axios.post('http://127.0.0.1:8000/api/movimentacoes/', dataToSend);
            }
    
            await updateProductQuantity(selectedProduct.id, product.tipo_movimentacao, parseInt(product.quantidade));
            await refreshProducts();
            clearForm();
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error.response ? error.response.data : error);
            alert("Erro: " + (error.response ? error.response.data.error : "Erro desconhecido."));
        }
    };
    

    return (
        <form onSubmit={handleSubmit} className="stock-movement-form">
            <div>
                <label>Produto:</label>
                <select name="produto" value={product.produto} onChange={handleChange} required>
                    <option value="">Selecione um produto</option>
                    {products.map((product) => (
                        <option key={product.id} value={product.id}>
                            {product.nome}
                        </option>
                    ))}
                </select>
            </div>
            <div>
                <label>Tipo de Movimentação:</label>
                <select name="tipo_movimentacao" value={product.tipo_movimentacao} onChange={handleChange} required>
                    <option value="entrada">Entrada</option>
                    <option value="saida">Saída</option>
                </select>
            </div>
            <div>
                <label>Quantidade:</label>
                <input
                    type="number"
                    name="quantidade"
                    value={product.quantidade}
                    onChange={handleChange}
                    placeholder="Quantidade"
                    required
                />
            </div>
            <div>
                <label>Motivo:</label>
                <input
                    type="text"
                    name="motivo"
                    value={product.motivo}
                    onChange={handleChange}
                    placeholder="Motivo"
                    required
                />
            </div>
            <button type="submit">{isEditing ? 'Atualizar' : 'Adicionar'}</button>
            {isEditing && <button type="button" onClick={clearForm}>Cancelar</button>}
        </form>
    );
};

export default StockMovementForm;
